                             <div className="absolute w-[160%] h-[2px] bg-white blur-[1px] rotate-90 shadow-[0_0_15px_white]"></div>
                             <div className="absolute w-[160%] h-[2px] bg-white blur-[1px] rotate-135 shadow-[0_0_15px_white]"></div>
                        </div>

